export const EXPANDED_QUIZZES = {
  ch1: { title:'Chapter 1 Quiz — What Is NSPIRE?', questions:[
    {q:'What does NSPIRE stand for?',opts:['National Standards for Property Inspection and Real Estate','National Standards for the Physical Inspection of Real Estate','New Standards for Physical Inspection of Residential Estates','National System for Property Inspection and Review Enforcement'],ans:1,exp:'NSPIRE = National Standards for the Physical Inspection of Real Estate. HUD\'s unified inspection standard replacing UPCS and HQS.'},
    {q:'Which system did NSPIRE replace for public housing and multifamily programs?',opts:['HQS only','UPCS only','Both UPCS and HQS','The REAC scoring system'],ans:2,exp:'NSPIRE replaced both UPCS (Uniform Physical Condition Standards) used for public housing/multifamily AND HQS (Housing Quality Standards) used for voucher programs.'},
    {q:'When did NSPIRE become effective for Public Housing and Multifamily programs?',opts:['January 1, 2023','October 1, 2023','January 1, 2024','October 1, 2024'],ans:1,exp:'NSPIRE became effective October 1, 2023 for Public Housing and Multifamily. HCV voucher programs transitioned after October 2024.'},
    {q:'Which item was scored under the old UPCS but is no longer cited at all under NSPIRE?',opts:['Missing smoke detectors','Exposed electrical wiring','Graffiti on building exterior','Carbon monoxide alarm missing'],ans:2,exp:'Graffiti was completely removed from NSPIRE. Other removed items: overgrown vegetation, exterior caulking, scratched countertops, damaged trim.'},
    {q:'How many calendar days advance notice do properties receive before a REAC inspection?',opts:['7 days','14 days','28 days','60 days'],ans:2,exp:'Properties receive 28 calendar days advance notice before a scheduled REAC inspection.'},
    {q:'What is the POA annual self-inspection requirement?',opts:['Inspect only units flagged in prior REAC inspection','Inspect all units at least once per year','Inspect only the REAC sample units','Inspect common areas and mechanical rooms only'],ans:1,exp:'POA self-inspections must cover ALL units at least once per year — not just the REAC sample. This is a separate annual compliance requirement from REAC.'},
    {q:'Which division of HUD conducts REAC inspections?',opts:['The Departmental Enforcement Center (DEC)','The Real Estate Assessment Center (REAC)','The Office of Housing (OH)','The Public and Indian Housing division (PIH)'],ans:1,exp:'REAC = Real Estate Assessment Center. HUD\'s division responsible for physical inspections of HUD-assisted housing.'},
    {q:'What is the primary shift in focus from UPCS to NSPIRE?',opts:['From interior focus to exterior focus','From appearance-focused scoring to health, safety, and function','From numerical scoring to pass/fail','From federal inspections to local inspections'],ans:1,exp:'NSPIRE\'s core shift is from appearance-focused scoring (how the property looks) to health, safety, and functional conditions — especially inside resident units.'},
    {q:'Why does your PCNA background transfer directly to NSPIRE pre-inspection work?',opts:['Because PCNA and NSPIRE use the same scoring software','Because the core skill — walk a property, identify what will be flagged, triage repairs, manage costs — is identical','Because you are already a licensed REAC inspector','Because PCNA work is required before NSPIRE inspections'],ans:1,exp:'The core workflow is identical: walk the property before a formal assessment, identify what will be cited, triage what needs fixing, manage remediation costs. Only the scoring standard is different.'},
    {q:'What is the HUD QA inspection (NSPIRE+)?',opts:['A higher-intensity version of REAC that scores more items','Quality assurance checks by HUD staff verifying that REAC inspectors are applying standards correctly','An additional inspection triggered by a property failing REAC','A self-inspection conducted by the property'],ans:1,exp:'NSPIRE+ (HUD QA inspection) is a quality assurance check performed by HUD staff on top of REAC inspections to verify that contractors are applying NSPIRE standards correctly.'},
    {q:'Which of the following is still cited and scored under NSPIRE?',opts:['Overgrown vegetation','Exterior caulking damage','Exposed electrical wiring in a unit','Scratched countertops'],ans:2,exp:'Exposed electrical wiring is a Life-Threatening deficiency still cited and scored. Overgrown vegetation, caulking, and scratched countertops were all removed from NSPIRE.'},
    {q:'Under NSPIRE, what does every deficiency standard include that UPCS did not?',opts:['A contractor cost estimate','A rationale explaining why that item is inspected and what risk the deficiency presents','A photo of what the deficiency looks like','A required repair method'],ans:1,exp:'Every NSPIRE deficiency includes a rationale — a specific explanation of the health, safety, or functional risk. This makes NSPIRE more transparent and defensible than UPCS.'},
    {q:'When HCV voucher programs transitioned to NSPIRE, what changed for landlords?',opts:['They now receive a 0–100 numerical score','They still use Pass/Fail but must now meet NSPIRE standards instead of HQS','They are no longer inspected at all','They must hire NSPIRE-certified inspectors'],ans:1,exp:'HCV programs transitioned from HQS to NSPIRE standards but still use Pass/Fail — no numerical score. The inspection criteria changed; the pass/fail structure did not.'},
    {q:'What is the market opportunity created by NSPIRE for your pre-inspection business?',opts:['NSPIRE scores are public, creating a directory of struggling properties','A large portion of the affordable housing market is still adjusting to a scoring system that now heavily weights units, creating demand for pre-inspection expertise','NSPIRE requires property owners to hire certified pre-inspection consultants','REAC now charges higher fees, creating budget for third-party consultants'],ans:1,exp:'NSPIRE\'s shift to unit-heavy scoring caught many property managers off guard. Those who scored well under UPCS are now failing because they never addressed unit conditions. That adjustment gap is where your service demand comes from.'},
    {q:'Which statement best describes how NSPIRE changed what gets scored on a property exterior?',opts:['Exterior items are scored more heavily now than under UPCS','Exterior scoring is identical to UPCS','Multiple exterior items like graffiti, vegetation, and caulking were removed; the exterior\'s total score weight dropped to 15%','Exterior items are now scored Pass/Fail instead of numerically'],ans:2,exp:'NSPIRE reduced the exterior\'s weight to 15% of the total score AND removed multiple previously scored exterior items (graffiti, vegetation, caulking, decorative fencing, trim). Exterior scoring matters much less than it did under UPCS.'},
  ]},

  ch2: { title:'Chapter 2 Quiz — The 3 Inspectable Areas', questions:[
    {q:'What percentage of the NSPIRE score comes from unit deficiencies?',opts:['25%','50%','60%','75%'],ans:2,exp:'Units carry 60% of the NSPIRE score — the most important structural fact in the entire scoring system.'},
    {q:'What is the score weight for the Inside inspectable area?',opts:['15%','25%','35%','40%'],ans:1,exp:'Inside areas (common areas, hallways, mechanical rooms) carry 25% of the score.'},
    {q:'What is the score weight for the Outside inspectable area?',opts:['5%','10%','15%','25%'],ans:2,exp:'Outside areas carry 15% of the score — the lowest of the three areas.'},
    {q:'A Life-Threatening deficiency in a unit vs. the same deficiency found outside — which deducts more points?',opts:['Outside — more exposed to the public','Unit — carries 60% weight vs. 15% for outside','They deduct the same points','Outside — harder to repair'],ans:1,exp:'Unit deficiencies always deduct more points because units carry 60% of the score weight vs. 15% for outside.'},
    {q:'Which of these is inspected in the Outside inspectable area?',opts:['Kitchen outlet GFCI protection','Common stairwell handrails','Parking lot trip hazards','Bathroom mold'],ans:2,exp:'Parking lots and trip hazards are Outside. Kitchen GFCI and bathroom mold are Unit. Stairwell handrails are Inside.'},
    {q:'Laundry rooms, mechanical rooms, and storage areas are part of which inspectable area?',opts:['Unit','Inside','Outside','Building systems (separate area)'],ans:1,exp:'Laundry rooms, mechanical rooms, and storage areas are all in the Inside inspectable area — everything inside the building that is not inside a unit.'},
    {q:'When building a remediation punch list, what items should be addressed first?',opts:['Outside Low deficiencies — easiest and cheapest to fix','Unit Life-Threatening items — highest score impact and 24-hour clock','Inside Severe items — common areas matter most','Whatever is cheapest per item to fix'],ans:1,exp:'Unit LT items are always first — highest point deduction, 24-hour correction clock, and most likely to cause a fail on their own at smaller properties.'},
    {q:'A property has a cracked sidewalk (Outside, Low) and a non-functional stove burner (Unit, Moderate). Which should be fixed first?',opts:['The sidewalk — it is a safety hazard','The stove burner — unit deficiencies carry more weight even at a lower severity','Fix both at the same time','The sidewalk, because it is a liability'],ans:1,exp:'Unit Moderate items always take priority over Outside Low items. The unit area carries 60% of the score; a Moderate unit deficiency deducts more than a Low outside deficiency.'},
    {q:'Which of these items was removed entirely from NSPIRE and should NOT be on your punch list?',opts:['Mold in bathroom','Non-functional kitchen exhaust fan','Overgrown vegetation','Damaged stair tread'],ans:2,exp:'Overgrown vegetation was completely removed from NSPIRE scoring. Mold, non-functional exhaust fans, and damaged stair treads are all still cited.'},
    {q:'What does the Inside area include that many people forget to inspect?',opts:['Individual unit bathrooms','Mechanical rooms, boiler rooms, and electrical rooms','The building exterior','Parking areas'],ans:1,exp:'Mechanical rooms, boiler rooms, and electrical rooms are part of the Inside inspectable area. These are commonly missed on pre-inspections but regularly cited by REAC inspectors.'},
    {q:'Why does the unit-heavy weighting of NSPIRE create a challenge for properties that scored well under UPCS?',opts:['UPCS allowed properties to pass with high exterior scores even if units were in poor condition','UPCS required more frequent inspections of units','Properties that passed UPCS paid lower fees','UPCS inspectors were less thorough than NSPIRE inspectors'],ans:0,exp:'Under UPCS, strong exterior and common area scores could offset poor unit conditions. NSPIRE\'s 60% unit weight means the same properties that coasted on curb appeal now fail because unit conditions dominate the score.'},
    {q:'Elevators in a building are part of which inspectable area?',opts:['Unit — residents use them daily','Inside — they are within the building but not inside a unit','Outside — mechanically separate system','They are not inspected under NSPIRE'],ans:1,exp:'Elevators are part of the Inside inspectable area — they are inside the building but not inside a residential unit.'},
    {q:'What is the correct order of priority for your pre-inspection punch list?',opts:['Outside first, then Inside, then Unit','Unit LT, Unit Severe, Inside LT, Unit Moderate, Inside Severe/Moderate, Outside','Whatever costs the least to fix first','Inside first since it affects all residents'],ans:1,exp:'Unit LT → Unit Severe → Inside LT → Unit Moderate → Inside Severe/Moderate → Outside. Always prioritize by area weight combined with severity.'},
    {q:'A property has pristine common areas and a perfect exterior but multiple Severe unit deficiencies. What does NSPIRE say?',opts:['The property likely passes because common areas and exterior look good','The property could still fail — unit deficiencies carry 60% of the score and the Unit Threshold rule applies','Common area scores compensate for unit issues under NSPIRE','The property gets a warning but does not fail'],ans:1,exp:'A perfect exterior and common areas cannot offset Severe unit conditions under NSPIRE. Units carry 60% of the score, and the Unit Threshold rule fails a property if 30+ unit deduction points are accumulated.'},
    {q:'Which statement about the Outside inspectable area is correct under NSPIRE?',opts:['Graffiti on the exterior is still scored as a Low deficiency','Exterior caulking damage is a Moderate deficiency','Security fencing with large gaps compromising resident safety is still cited','All exterior items were removed from NSPIRE'],ans:2,exp:'Security and safety fencing damage is still cited under NSPIRE. Graffiti, exterior caulking, overgrown vegetation, and decorative fencing damage were all removed.'},
  ]},

  ch3: { title:'Chapter 3 Quiz — The 4 Severity Levels', questions:[
    {q:'The 24-hour correction clock for a Life-Threatening deficiency pauses on weekends. True or false?',opts:['True — HUD allows weekend pauses','True — only for federal holidays','False — clock never pauses for nights, weekends, or holidays','False — but it pauses after 10pm'],ans:2,exp:'False. The 24-hour LT correction clock NEVER pauses. Cited at 3pm Friday = deadline at 3pm Saturday.'},
    {q:'What symbol on an NSPIRE report indicates a carbon monoxide alarm deficiency?',opts:['* (asterisk)','^ (caret)','+ (plus sign)','# (hash)'],ans:2,exp:'+ indicates a CO alarm deficiency. * indicates a smoke detector deficiency. Both require 24-hour correction but are not scored.'},
    {q:'What is the correction timeframe for a Moderate deficiency?',opts:['24 hours','7 days','30 days','60 days'],ans:2,exp:'Moderate = 30 days. Low = 60 days. LT and some Severe = 24 hours.'},
    {q:'What is the correction timeframe for a Low deficiency?',opts:['24 hours','30 days','60 days','90 days'],ans:2,exp:'Low deficiencies must be corrected within 60 days. Moderate = 30 days.'},
    {q:'What must a property do if an LT deficiency cannot be permanently fixed within 24 hours?',opts:['Wait until Monday and call REAC','Provide temporary mitigation AND contact HUD in writing for an extended timeframe before the deadline','Do nothing — 72 hours is actually acceptable','File an appeal to pause the clock'],ans:1,exp:'Must provide temporary mitigation (block the hazard) AND contact HUD in writing before the 24-hour deadline to receive an approved extended timeframe.'},
    {q:'What is the Health and Safety Report?',opts:['A monthly report the property submits to HUD','A report given to the property at the end of each inspection day listing all LT and Severe deficiencies found that day','The final inspection report showing the score','A report filed by the property manager after repairs are complete'],ans:1,exp:'The Health and Safety Report is issued to the property at the end of each inspection day. It lists all LT and Severe deficiencies found that day and starts the 24-hour correction clock.'},
    {q:'Which deficiency category covers items that exist but do not work as designed?',opts:['Health and Safety','Function and Operability','Condition and Appearance','Life-Threatening'],ans:1,exp:'Function and Operability covers items that exist but don\'t work as designed — a stove burner that won\'t ignite, broken window latch, non-functioning elevator.'},
    {q:'A property\'s inspection report shows "76*". What does this mean?',opts:['The property scored 76 and is under appeal','The property scored 76 but has at least one smoke detector deficiency requiring 24-hour correction','The property scored 76 with a CO alarm deficiency','The property barely passed and is on a watch list'],ans:1,exp:'* after the score means at least one smoke detector deficiency was found. The property scored 76 (pass) but must correct smoke detector issues within 24 hours.'},
    {q:'Evidence of repair for a Life-Threatening deficiency must be submitted within how many hours of the original inspection?',opts:['24 hours','48 hours','72 hours','96 hours'],ans:2,exp:'Evidence of repair must be submitted within 48 hours of the 24-hour deadline — that is 72 hours total from the time of the original inspection.'},
    {q:'The Condition and Appearance deficiency category covers what type of issues?',opts:['Items presenting direct health or safety risk','Items that exist but don\'t function','Items that are deteriorated or damaged in ways affecting long-term integrity','Items that require immediate Life-Threatening correction'],ans:2,exp:'Condition and Appearance covers items that are deteriorated or damaged — cracked walls, water-stained ceilings, corroded plumbing. Severity varies based on the extent and implications of the deterioration.'},
    {q:'A property receives a Health and Safety Report at the end of day 1 of a 3-day inspection. When does the 24-hour clock expire for items on that report?',opts:['After day 3 of the inspection is complete','24 hours after the report is issued at the end of day 1','After the full inspection report is released','48 hours after the last day of inspection'],ans:1,exp:'The 24-hour clock starts when the Health and Safety Report is issued — at the end of day 1. The property cannot wait until the full inspection is complete.'},
    {q:'Why do some Severe deficiencies have a 24-hour correction timeframe rather than 30 days?',opts:['All Severe items have a 30-day timeframe — there is no 24-hour Severe','Specific Severe deficiencies related to physical security or immediate injury risk require 24-hour correction','Severe items in units are 24 hours; Severe items outside are 30 days','It depends on whether the property has had prior failures'],ans:1,exp:'Some Severe deficiencies — specifically those that present immediate physical security or serious injury risks — have a 24-hour correction requirement. The specific timeframe is listed in the NSPIRE standard for each deficiency.'},
    {q:'What does the ^ (caret) symbol after a NSPIRE score indicate?',opts:['The property is under DEC review','At least one CO alarm deficiency was found','At least one deficiency not yet scored during the transition period was found','The score is being audited by REAC QA'],ans:2,exp:'^ means at least one deficiency that will not be scored until the end of the transition period was found. These still require correction — only the point deduction is delayed.'},
    {q:'Your client asks why they need to fix a smoke detector if it\'s "not scored." How do you explain this?',opts:['They don\'t — unscored items can be ignored','Not scored means it doesn\'t deduct points, but it still requires 24-hour correction and appears on the report with a * symbol','Unscored items only need to be fixed if a resident complains','Not scored means a 60-day correction window applies'],ans:1,exp:'Not scored means zero point deduction, but the 24-hour correction requirement still applies. A * on the report means a smoke detector deficiency was found and must be corrected within 24 hours.'},
    {q:'The Severe deficiency category includes deficiencies that present what type of risk?',opts:['High risk of death','High risk of permanent disability, serious injury, or compromise of physical security','Moderate risk of a healthcare visit','Minor cosmetic or functional issues'],ans:1,exp:'Severe = high risk of permanent disability, serious injury or illness, or that would seriously compromise the physical security or safety of a resident or their property.'},
    {q:'A property has a mix of deficiencies. Which combination creates the most urgency for your client?',opts:['5 Low outside deficiencies','3 Moderate unit deficiencies','2 Life-Threatening unit deficiencies','4 Severe inside deficiencies'],ans:2,exp:'Life-Threatening unit deficiencies are always the most urgent — they trigger the 24-hour correction clock, carry the largest point deductions, and are in the highest-weighted area (units = 60%).'},
  ]},

  ch4: { title:'Chapter 4 Quiz — Scoring Mechanics', questions:[
    {q:'A property\'s overall calculated score is 68, but 33 points came from unit deficiencies alone. What is the official result?',opts:['Pass — score is 68','Fail — Unit Threshold triggered, score capped at 59','Pass with a mandatory corrective action plan','Fail only if at least one LT item was present'],ans:1,exp:'Unit Threshold: if 30 or more points are deducted from unit deficiencies alone, the property fails regardless of overall score. Official score is capped at 59.'},
    {q:'What score triggers an automatic mandatory referral to HUD\'s Departmental Enforcement Center?',opts:['Below 60','Below 50','Below 40','30 or below'],ans:3,exp:'Score of 30 or below = automatic mandatory DEC referral. Two consecutive scores below 60 = discretionary (may be) referred.'},
    {q:'How does the Defect Impact Weight formula normalize for property size?',opts:['It divides by building square footage','It divides by the number of buildings on the property','It divides the total deduction by the number of units inspected','It multiplies deductions by an inspection year factor'],ans:2,exp:'The total point deduction is divided by the number of units inspected. This normalizes for size — larger properties face smaller per-inspection deductions for the same deficiency.'},
    {q:'The same type of deficiency appears in 8 different units during a REAC inspection. How many times is it scored?',opts:['8 separate deductions','Cited 8 times but scored only once per inspectable area (duplicate defects rule)','Only the worst instance is cited','Not scored if found more than 3 times'],ans:1,exp:'Duplicate defects rule: same deficiency type in the same inspectable area = cited every time but scored only once. Point deduction is applied once, not 8 times.'},
    {q:'Which property scoring range should be your primary target for new pre-inspection clients?',opts:['90 or above — they have the most maintenance budget','60–70 — passing but vulnerable, motivated to protect their score','30 or below — most urgent need for help','All ranges are equally good targets'],ans:1,exp:'Properties scoring 60–70 are passing but barely. They\'re in a fragile position, motivated, and usually have known deferred maintenance. These are the easiest to convert.'},
    {q:'A Life-Threatening unit deficiency at a 20-unit property has a base deduction of 60 points. How many points does it actually deduct from the score?',opts:['60 points','20 points','3 points','6 points'],ans:2,exp:'Deduction = base value ÷ units inspected. 60 ÷ 20 units = 3 points. The normalization prevents a single deficiency from causing an automatic fail at larger properties.'},
    {q:'What are the two independent ways a property can fail an NSPIRE inspection?',opts:['Score below 60, OR having any LT deficiency present','Score below 60 (Property Threshold), OR 30+ points deducted from unit deficiencies alone (Unit Threshold)','Score below 60, OR receiving a DEC referral','Score below 70, OR having two or more Severe items'],ans:1,exp:'Two ways to fail: (1) Overall score below 60 — Property Threshold, (2) 30+ points deducted from unit deficiencies alone — Unit Threshold. Either one alone causes a fail.'},
    {q:'How does NSPIRE inspection frequency change after a property fails?',opts:['Inspection frequency stays the same regardless of score','The property is inspected more frequently after a fail','The property is exempt from inspections for 1 year while it remediates','Failing automatically triggers a quarterly inspection schedule'],ans:1,exp:'Properties with lower scores are inspected more frequently. A fail brings the next inspection sooner. This is why your pre-inspection service prevents a cascade — one pass buys 2–3 years.'},
    {q:'Two successive REAC inspection scores come in at 57 and 54. What is the consequence?',opts:['Automatic mandatory DEC referral','The property may (discretionary) be referred to HUD\'s DEC for evaluation','Nothing until a third consecutive failure','Immediate contract termination'],ans:1,exp:'Two consecutive scores below 60 = discretionary DEC referral. "May" be referred — not mandatory. Automatic mandatory referral only triggers at a score of 30 or below.'},
    {q:'Why does your pre-inspection service create more value for smaller properties than larger ones?',opts:['Smaller properties have more units to inspect','At smaller properties, each deficiency deducts more points because deductions are divided by fewer units','Larger properties have better maintenance programs','Smaller properties have simpler systems to evaluate'],ans:1,exp:'Defect Impact Weight = base deduction ÷ units inspected. At a 10-unit property, one LT item deducts 6 points. At a 100-unit property, the same item deducts 0.6 points. Small properties are highly vulnerable to individual deficiencies.'},
    {q:'The duplicate defects rule means a property does NOT need to fix all instances of a repeated deficiency. True or false?',opts:['True — if scored only once, only one instance needs to be fixed','False — compliance requires correcting all instances within the required timeframe even though only one is scored'],ans:1,exp:'False. The duplicate defects rule affects scoring only — it reduces the point deduction. All instances still need to be corrected within the required timeframe for compliance.'},
    {q:'A property scores 71 overall. Of that deduction, 32 points came from the Outside area and 26 points from units. What is the result?',opts:['Fail — Unit Threshold triggered','Pass — score is 71 and unit deductions are below 30','Fail — overall score is below 75','Conditional pass'],ans:1,exp:'The overall score is 71 (above 60) and unit deductions are 26 points (below the 30-point Unit Threshold). Both thresholds are passed — this is a legitimate pass.'},
    {q:'What happens to the inspection frequency for a property consistently scoring 90 or above?',opts:['They are inspected every year regardless','They qualify for the longest inspection cycle — approximately every 3 years','They are permanently exempt from REAC inspections','They can request biennial inspections'],ans:1,exp:'Properties scoring 90 or above qualify for approximately a 3-year inspection cycle. Higher scores = longer time between REAC visits = more years of stability your service can secure for a client.'},
    {q:'Which statement correctly describes the DEC (Departmental Enforcement Center)?',opts:['The DEC conducts REAC physical inspections','The DEC evaluates properties with very low scores and can require management changes, contract modifications, or termination','The DEC issues elevator and boiler certificates','The DEC manages the 24-hour correction process'],ans:1,exp:'The DEC evaluates at-risk properties — gathering input from tenants, officials, and staff. Can lead to required management changes, contract modifications, or in extreme cases, contract termination.'},
    {q:'A property has a calculated score of 55 after a REAC inspection. The inspector found 2 LT unit items and 5 Moderate inside items. What should the property prioritize first?',opts:['The 5 Moderate inside items — there are more of them','The 2 LT unit items — Life-Threatening items trigger the 24-hour clock regardless of score','Get the score appealed first, then fix items','Fix the cheapest items first'],ans:1,exp:'LT items ALWAYS come first — the 24-hour clock is running regardless of the score. Even while managing a failed inspection, LT corrections take immediate priority.'},
  ]},

  ch5: { title:'Chapter 5 Quiz — Life-Threatening Deficiencies', questions:[
    {q:'A unit entry door is missing. How is it classified under NSPIRE?',opts:['Low — 60 day fix','Moderate — 30 day fix','Severe — 24 hour or 30 day fix','Life-Threatening — 24 hour fix'],ans:3,exp:'Unit entry doors are Life-Threatening — even non-fire-labeled doors, because they provide fire, smoke, and security protection for residents.'},
    {q:'Egress requirements under NSPIRE apply to which specific windows?',opts:['All windows in units on all floors','Living room and bedroom windows on floors 1–5','Bedroom windows only, floors 1–3 only','All windows on the first two floors'],ans:2,exp:'Egress applies to bedroom windows only, and only for units on the 3rd floor and below. Living room windows do not count for egress unless a fire escape is present.'},
    {q:'A missing light bulb in a unit — how is it correctly classified?',opts:['Life-Threatening — exposed electrical conductor','Severe — electrical hazard','Moderate or Low — a lighting fixture deficiency, NOT an exposed conductor','Not cited under NSPIRE'],ans:2,exp:'A missing light bulb is NOT an LT exposed conductor. It is a fixture deficiency (Moderate or Low). This is a common inspector error — directly appealable if incorrectly cited.'},
    {q:'A handrail on a common stairway is missing. Mounting holes are visible in the wall. Severity?',opts:['Low — handrails are cosmetic','Moderate — 30 day fix','Severe — 24 hour or 30 day fix','Life-Threatening — 24 hour fix'],ans:3,exp:'Missing handrail WHERE evidence of prior installation exists = Life-Threatening. If NO evidence of prior installation exists, it is a separate, currently non-scored deficiency.'},
    {q:'As of December 29, 2024, what is required of battery-only smoke detectors?',opts:['They must be replaced with hardwired detectors immediately','They must have sealed, tamper-proof batteries','They must be tested monthly and logged','They are no longer acceptable in any form'],ans:1,exp:'As of December 29, 2024, battery-only smoke detectors must have sealed tamper-proof batteries. Standard removable batteries are now deficient if that is the sole power source.'},
    {q:'Water is dripping from a ceiling leak onto an electrical outlet below. How is this classified?',opts:['Low — it\'s just a water leak','Moderate — water damage only','Severe — two separate deficiencies','Life-Threatening — new Leak-Electrical deficiency'],ans:3,exp:'Water currently in contact with an electrical conductor is a Life-Threatening deficiency called "Leak-Electrical" — added as a new deficiency under NSPIRE.'},
    {q:'You detect a gas odor in a unit during your pre-inspection walkthrough. What do you do?',opts:['Note it on the punch list and continue','Turn off the gas valve in the unit and keep walking','Stop the inspection immediately, evacuate, and call the gas utility and fire department','Open the windows for ventilation and continue'],ans:2,exp:'Gas odor = Life-Threatening. Stop the inspection, evacuate the building, and call the gas utility and fire department. Do not continue the walkthrough.'},
    {q:'A unit entry door has a broken latch and swings open on its own. It is NOT a fire-labeled door. Is it Life-Threatening?',opts:['No — only fire-labeled doors are LT under NSPIRE','Yes — entry doors were elevated to LT even if not fire-labeled','No — broken latch is Moderate','Only if the unit is on a floor above grade'],ans:1,exp:'Yes — Life-Threatening. The final NSPIRE standards elevated ALL unit entry doors to LT, not just fire-labeled ones. A door that doesn\'t latch cannot protect residents from fire, smoke, or security threats.'},
    {q:'A carbon monoxide alarm is missing in a unit that has a gas stove. What appears on the NSPIRE report and what is required?',opts:['Cited as Severe; 30-day correction','Cited with + symbol; Life-Threatening; 24-hour correction; not deducted from score','Cited as Moderate; 30-day correction','Not cited if smoke detectors are present'],ans:1,exp:'Missing CO alarm = Life-Threatening. Marked with + on the report. Not scored (no point deduction) but requires 24-hour correction.'},
    {q:'You are walking a unit on the 2nd floor. The bedroom window is painted shut and cannot be opened. Severity?',opts:['Low — cosmetic condition','Moderate — window maintenance issue','Life-Threatening — blocked egress on floor 1–3','Not cited — egress only applies to floors 1 and 2'],ans:2,exp:'Bedroom window on floors 1–3 that cannot open for emergency exit = Life-Threatening blocked egress. This is a common finding in older buildings where windows are repeatedly painted.'},
    {q:'A handrail is missing on a stairway and there is NO evidence (no holes, no paint shadow, no hardware) that one was ever installed. How is this treated?',opts:['Life-Threatening — same as evidence present','Severe — still requires correction','Currently non-scored deficiency — no point deduction, though HUD monitors this data','Low — 60 day fix'],ans:2,exp:'No evidence of prior installation = currently non-scored deficiency. No points deducted. HUD is collecting data on this to consider future requirements.'},
    {q:'You are testing a smoke detector during a pre-inspection and it does not activate when you press the test button. What do you do?',opts:['Note it as Low and move on','Cite it as Life-Threatening on your punch list — 24-hour correction required after the REAC inspection','Replace the battery and retest; if still non-functional, cite as LT requiring correction','Document it but don\'t prioritize since smoke detectors aren\'t scored'],ans:2,exp:'Non-functional smoke detector = LT deficiency. Replace battery and retest — if still non-functional, the detector must be replaced. While not scored, it requires 24-hour correction and appears on the REAC report with *.'},
    {q:'Why should you carry smoke detector test spray on every pre-inspection walkthrough?',opts:['It is required by NSPIRE regulations','It activates the detector without climbing to press each one manually — faster on large properties','It tests both smoke detectors and CO alarms simultaneously','It provides a permanent record of each detector tested'],ans:1,exp:'Test spray activates the alarm\'s sensor without physically pressing each unit. On a 100-unit property with multiple detectors per unit, this saves significant time.'},
    {q:'What is the standard for a unit entry door to be considered adequate under NSPIRE?',opts:['The door must be fire-labeled','The door must close, latch, and have functional locks — providing fire, smoke, and security protection','The door must have a deadbolt and a peephole','The door must open outward for emergency exit'],ans:1,exp:'An adequate unit entry door closes, latches, and has functional locks. It must provide basic protection from fire, smoke, and security threats. Missing = LT. Non-latching = LT.'},
    {q:'Which combination below represents the most critical findings on a pre-inspection walkthrough?',opts:['5 outdoor trip hazards, 3 damaged door knobs, missing stair tread','1 unit with exposed wiring + a CO alarm missing + 2 bedroom windows painted shut on floor 2','3 moderate plumbing leaks + 1 non-functional light fixture + 2 low door deficiencies','4 missing weather strips + 2 cracked exterior walls + 1 inoperable stove burner'],ans:1,exp:'Exposed wiring (LT), missing CO alarm (LT), and blocked egress windows (LT) are three separate Life-Threatening deficiencies requiring 24-hour correction and carrying the largest point deductions.'},
  ]},

  ch6: { title:'Chapter 6 Quiz — Severe & Moderate Deficiencies', questions:[
    {q:'An outlet 4 feet from the kitchen sink has no GFCI protection. Severity?',opts:['Low','Moderate','Severe','Life-Threatening'],ans:2,exp:'Unprotected outlet within 6 feet of any water source = Severe. Most common deficiency in NSPIRE at approximately 13.4 per 100 units.'},
    {q:'Three-prong outlet shows "open ground" on an outlet tester. Severity?',opts:['Low','Moderate','Severe','Life-Threatening'],ans:2,exp:'Open ground on a three-prong outlet = Severe. Removes the safety ground that protects residents from electrical shock.'},
    {q:'Which is no longer scored under NSPIRE?',opts:['Missing GFCI outlet','Mold in bathroom','Overgrown vegetation','Exposed electrical wiring'],ans:2,exp:'Overgrown vegetation was removed from NSPIRE scoring entirely.'},
    {q:'A stove has 4 burners. One doesn\'t produce heat. The other 3 work fine. Severity?',opts:['Low','Moderate — at least one other burner works','Severe — appliance is partially non-functional','Life-Threatening'],ans:1,exp:'When at least one other burner works = Moderate. If NO burners work at all, severity escalates to Severe.'},
    {q:'When treating mold in a unit, what must be addressed first?',opts:['The mold surface — bleach it immediately','The source of moisture causing the mold — fix the leak or condensation issue first','Notify the tenant first','Get REAC pre-approval before any mold remediation'],ans:1,exp:'Fix the moisture source first. Bleach treats surface mold but the mold returns if the underlying moisture problem remains unresolved.'},
    {q:'Peeling paint in a pre-1978 building triggers what requirement beyond NSPIRE scoring?',opts:['Nothing — NSPIRE is the only standard that applies','Lead paint regulations under 24 CFR Part 35 requiring lead-safe work practices','Immediate tenant relocation','Historic preservation review before any repairs'],ans:1,exp:'Pre-1978 peeling paint triggers lead paint regulations (24 CFR Part 35) — requiring lead-safe work practices. A regulatory issue beyond and in addition to NSPIRE scoring.'},
    {q:'You are under the kitchen sink during a pre-inspection and the wood is soft and discolored but there is no active drip. What do you cite?',opts:['Nothing — no active leak means no deficiency','Low — minor cosmetic damage','Moderate — evidence of past or current water damage indicating a plumbing issue','Severe — structural concern'],ans:2,exp:'Soft, discolored cabinet floor under a sink indicates past or ongoing water damage even without an active drip at the moment. Cite as Moderate and identify the source — a slow leak, failed drain connection, or supply line seep.'},
    {q:'What is the approximate rate of the most common Severe deficiency in NSPIRE per 100 units?',opts:['About 2 per 100 units','About 6 per 100 units','About 13 per 100 units','About 25 per 100 units'],ans:2,exp:'Unprotected outlet within 6 feet of water is the most common deficiency at approximately 13.4 per 100 units. Using an outlet tester on every kitchen and bathroom outlet will catch this consistently.'},
    {q:'A permanently installed bathroom vanity light fixture does not turn on after you replace the bulb. Severity?',opts:['Low — just a dead bulb','Moderate — permanently installed fixture is inoperable','Severe — electrical hazard','Life-Threatening'],ans:1,exp:'Permanently installed light fixture inoperable (after confirming the bulb is good) = Moderate at approximately 2.6 per 100 units.'},
    {q:'An outlet in the bathroom is 8 feet from the sink. Does it need GFCI protection?',opts:['Yes — all bathroom outlets require GFCI protection regardless of distance','No — GFCI is only required within 6 feet of water sources','Yes — all outlets in wet areas need GFCI','No — 8 feet is safe enough'],ans:0,exp:'All bathroom outlets require GFCI protection regardless of distance from the water source. The 6-foot rule applies to outlets near sinks in kitchens and other areas; bathrooms require GFCI on all outlets.'},
    {q:'Mold is found in multiple rooms of a unit where an elderly resident with COPD lives. How does this affect the severity classification?',opts:['It doesn\'t — mold is always Severe regardless of residents','The presence of a vulnerable resident with a respiratory condition can escalate mold to Life-Threatening','The resident\'s condition must be formally documented before severity changes','It only changes severity if the mold covers more than 10 square feet'],ans:1,exp:'Mold is Severe in most cases, but the presence of vulnerable residents (children, elderly, residents with respiratory conditions like COPD) can escalate mold to Life-Threatening severity.'},
    {q:'What tool should you carry on every pre-inspection to catch the most common Severe electrical deficiency?',opts:['A voltage tester pen','A plug-in outlet tester ($10–15 at any hardware store)','A multimeter','An infrared camera'],ans:1,exp:'A plug-in outlet tester instantly shows open ground, reverse polarity, and open neutral conditions. It catches both GFCI-absent Severe deficiencies and grounding Severe deficiencies in seconds per outlet.'},
    {q:'You find the water heater in a unit is 17 years old and functional. What do you do?',opts:['Nothing — it\'s working fine','Flag it for near-term replacement even though it\'s currently operational; 17 years exceeds rated life of 8–12 years','Cite it as a Moderate deficiency for age alone','Require immediate replacement before the REAC inspection'],ans:1,exp:'A 17-year-old water heater has significantly exceeded its rated 8–12 year life. Flag it for proactive replacement — the cost of planned replacement is far less than emergency repair when it fails right before or after an inspection.'},
    {q:'Common area paint deterioration in a post-1978 property — cited under NSPIRE?',opts:['Yes — Moderate deficiency','Yes — Low deficiency','No — removed from NSPIRE scoring','Only if it affects more than 20% of a surface'],ans:2,exp:'Common area paint deterioration in post-1978 properties was removed from NSPIRE scoring. This is one of the items that wasted maintenance budgets under UPCS — redirect those dollars to scored items.'},
    {q:'A bathroom exhaust fan is completely non-functional and the window in the bathroom does not open. Severity?',opts:['Low — cosmetic ventilation issue','Moderate — no functional ventilation in a wet area','Severe — creates immediate health hazard','Life-Threatening'],ans:1,exp:'No functional ventilation in a bathroom (no fan AND no operable window) = Moderate. Without ventilation, moisture accumulates and leads directly to mold — one of the highest-frequency Severe deficiencies.'},
  ]},

  ch7: { title:'Chapter 7 Quiz — HCV vs. Scored Programs', questions:[
    {q:'What type of result does an HCV Section 8 voucher inspection produce?',opts:['A score from 0–100','Pass or Fail only — no numerical score','A score from 0–60','A letter grade A through F'],ans:1,exp:'HCV and PBV programs use Pass/Fail only — no numerical score. Any Life-Threatening or Severe deficiency causes a fail.'},
    {q:'What is the immediate financial consequence for an HCV landlord whose unit fails inspection and corrections are not made in time?',opts:['A $500 fine per deficiency','The Housing Assistance Payment (HAP) can be suspended until corrections are made','The tenant is automatically relocated at the landlord\'s expense','The landlord is immediately removed from the HCV program'],ans:1,exp:'Failed HCV inspections can lead to HAP suspension — the landlord stops receiving the monthly Section 8 payment for that unit until deficiencies are corrected.'},
    {q:'Why is the REAC sample important for your pre-inspection business pitch?',opts:['Larger samples mean lower REAC fees','The sample is randomly selected — you can\'t control which units get inspected, so every unit must be inspection-ready','The sample favors newer units in a portfolio','A smaller sample is easier to pass'],ans:1,exp:'REAC sample is randomly selected. The only guaranteed way to produce a good score is making sure every unit is ready on any given day — not just the ones you think might be sampled.'},
    {q:'How does your pre-inspection walkthrough create dual value for a multifamily property owner?',opts:['It replaces the REAC inspection entirely','It satisfies the annual POA self-inspection compliance requirement AND prepares the property for REAC','It reduces REAC inspection fees','It provides an exemption from the unit threshold rule'],ans:1,exp:'Your walkthrough satisfies the annual POA self-inspection compliance requirement AND prepares the property for REAC — two separate requirements handled with one engagement.'},
    {q:'Which HCV landlord is the easiest to convert as your first client?',opts:['A landlord with a perfect inspection history — they have the most budget','A landlord who just failed an inspection — highly motivated and already experiencing the pain','A landlord with only 1–2 HCV units — lower complexity','A landlord who has never heard of NSPIRE — educational sale'],ans:1,exp:'A landlord who just failed an inspection is the easiest to convert — the pain is immediate and real, they\'re highly motivated, and they need help right now.'},
    {q:'What is the approximate inspection frequency for a property consistently scoring 90 or above?',opts:['Every year','Every 2 years','Every 3 years','Every 5 years'],ans:2,exp:'Properties scoring 90+ qualify for approximately a 3-year inspection cycle — the longest available. Your pre-inspection service helps clients maintain high scores and stay in this cycle.'},
    {q:'A multifamily property has 80 units. REAC samples 30 of them. The property owner asks why they should bother fixing units that weren\'t in the sample. What do you tell them?',opts:['They\'re right — only fix the sampled units to save money','The sample changes every inspection — a unit not sampled today will likely be sampled next time, and the POA self-inspection requires all units anyway','Only common area deficiencies matter between inspections','HUD publishes the sample list in advance'],ans:1,exp:'The sample is random each inspection. Today\'s unsampled bad units become next inspection\'s score-killers. Plus the annual POA self-inspection requires all units to meet NSPIRE standards regardless of the REAC sample.'},
    {q:'A property scored 62 on its last inspection. What does this mean for inspection frequency and your service value?',opts:['They are in the 3-year cycle and have low urgency','They are in a shorter cycle and one more subpar inspection could trigger a fail — your service is urgent and valuable','They have been referred to DEC already','They are permanently exempt from future inspections'],ans:1,exp:'A score of 62 is a marginal pass. These properties are likely in the 2-year or shorter cycle, and any deterioration in condition could push them below 60. High motivation, high service value.'},
    {q:'Under NSPIRE, which programs still use a numerical 0–100 score?',opts:['HCV voucher programs only','Public Housing and Multifamily (PBRA) programs','All HUD programs equally','Project-Based Voucher programs'],ans:1,exp:'Public Housing and Multifamily (PBRA) properties receive 0–100 numerical scores. HCV and PBV programs use Pass/Fail only.'},
    {q:'What is PBRA and how is it inspected under NSPIRE?',opts:['Project-Based Rental Assistance — uses Pass/Fail like HCV','Project-Based Rental Assistance — receives 0–100 numerical NSPIRE score','Property-Based Risk Assessment — a pre-inspection tool','Pre-Building Regulatory Audit — conducted by the DEC'],ans:1,exp:'PBRA = Project-Based Rental Assistance. These multifamily properties receive a 0–100 numerical NSPIRE score with the same pass/fail threshold and Unit Threshold rules as public housing.'},
    {q:'An HCV landlord has 15 voucher units averaging $1,400/month HAP. If all 15 units fail and HAP is suspended for 2 months during corrections, what is the revenue impact?',opts:['$1,400','$14,000','$42,000','$21,000'],ans:2,exp:'15 units × $1,400/month × 2 months = $42,000 in suspended HAP income. This is your strongest pitch: your pre-inspection fee is a fraction of the risk your service eliminates.'},
    {q:'The POA self-inspection is required for which type of properties?',opts:['HCV/voucher properties only','Public Housing and Multifamily properties with HUD assistance contracts','All residential properties in the US','Only properties that failed their last REAC inspection'],ans:1,exp:'POA self-inspections are required for Public Housing and Multifamily properties with HUD assistance contracts. Must cover ALL units annually.'},
    {q:'What is the best way to frame your pre-inspection service\'s value to a property management company with 8 affordable housing properties?',opts:['Emphasize how much you know about NSPIRE regulations','Show them that one engagement covers multiple properties and that a single failed inspection across their portfolio could cost more than your annual service fee','Offer the cheapest price possible to win the business','Focus on the cosmetic improvements you can drive'],ans:1,exp:'One relationship = multiple properties. Frame the risk of a single failed inspection (score + correction costs + HAP impacts) against your service fee. The math works strongly in your favor at a portfolio level.'},
    {q:'What does the POA self-inspection requirement create for your service business?',opts:['A legal liability — you become responsible for compliance','A mandatory annual revenue opportunity — properties must inspect all units, and your service fulfills that requirement','A competitive barrier — only licensed inspectors can conduct self-inspections','Nothing — it is a paperwork exercise with no real impact'],ans:1,exp:'The annual POA self-inspection requirement is a recurring compliance obligation. Your service fulfills it, giving property owners a reason to hire you every year — not just before a REAC inspection.'},
    {q:'A property scored 75 on its last inspection 18 months ago. Is there urgency for your pre-inspection service?',opts:['No — they passed well and won\'t be inspected for 3 years','Yes — if they are in the 2-year cycle, an inspection could be coming within 6 months and conditions may have changed','Only if they have had maintenance complaints','No — a score of 75 is safe and no preparation is needed'],ans:1,exp:'A score of 75 puts the property in the 2-year cycle. If the inspection was 18 months ago, another could come in 6 months or less. Conditions change. Deferred maintenance accumulates. This is exactly the right time to engage.'},
  ]},

  ch8: { title:'Chapter 8 Quiz — Appeals & Building Your Business', questions:[
    {q:'Approximately what percentage of appealed deficiencies were successfully overturned in early NSPIRE data?',opts:['About 10%','About 25%','About 44%','About 65%'],ans:2,exp:'About 44% of submitted deficiency appeals were successful — a meaningful rate that makes the appeals process a real add-on service opportunity.'},
    {q:'Filing an appeal pauses the 24-hour correction clock for LT items. True or false?',opts:['True — filing an appeal automatically suspends all correction clocks','False — corrections must still be made within required timeframes even while an appeal is pending'],ans:1,exp:'False. Appeals do NOT pause correction requirements. The property must fix or mitigate the deficiency within the required timeframe. Appeals are about adjusting the score — not delaying the fix.'},
    {q:'A missing light bulb was cited on a REAC report as a Life-Threatening exposed electrical conductor. What should you do?',opts:['Accept it — the inspector\'s judgment is authoritative','Appeal it — this directly contradicts NSPIRE standard language which explicitly excludes missing bulbs from the exposed conductor definition','Fix the bulb and don\'t appeal — it\'s not worth the effort','Request a re-inspection instead of filing an appeal'],ans:1,exp:'A missing light bulb cannot be an LT exposed conductor under NSPIRE. The standard explicitly excludes this. This is an incorrect citation and is directly appealable.'},
    {q:'What is the correct pricing model for Phase 2 — Remediation Management?',opts:['Flat rate of $500 per unit regardless of scope','Hourly rate only — never percentage based','Percentage of project savings or flat management fee (5–15% of project cost)','Commission paid by the contractors you refer'],ans:2,exp:'Remediation management is best priced as a percentage of project savings or a flat management fee of 5–15% of project cost. This aligns your incentive with saving the client money.'},
    {q:'What is the most valuable first-client strategy for launching your business?',opts:['Charge full rates from day one to establish perceived value','Offer a discounted first engagement in exchange for a documented case study and testimonial','Target the largest property you can find regardless of readiness','Focus only on HCV landlords before approaching multifamily owners'],ans:1,exp:'A discounted first engagement in exchange for a documented case study with specific numbers — score improvement, dollars saved — is the right move. One strong case study opens more doors than any marketing material.'},
    {q:'Which type of evidence is most useful when appealing an infestation deficiency?',opts:['A photograph of the unit taken after cleaning','Pest control service records with dates, treatments, and technician signature','A letter from the tenant saying they haven\'t seen pests','A contractor estimate for new cabinets'],ans:1,exp:'Active pest control contracts with service logs showing treatment dates and methods are the strongest evidence for infestation appeals. Showing that the property had an active pest management program can overturn the citation.'},
    {q:'What is the approximate pricing range for a pre-inspection walkthrough service?',opts:['$5–10 per unit, minimum $500','$15–35 per unit, minimum $1,500–2,500','$50–100 per unit, minimum $10,000','Flat fee of $2,000 regardless of size'],ans:1,exp:'Pre-inspection walkthroughs are typically priced at $15–35 per unit with a minimum engagement of $1,500–2,500. This scales reasonably and positions your service well against the cost of a failed inspection.'},
    {q:'Why is the NSPIRE appeals success rate (approximately 44%) significant for your business?',opts:['It means most inspections are wrong and properties should always appeal','It creates a meaningful post-inspection service — helping clients identify appealable items and compile the documentation package to recover points','It means you should advise clients not to fix deficiencies and just appeal instead','It only applies to large properties with legal staff'],ans:1,exp:'A 44% success rate means that nearly half of all submitted appeals succeed. This creates a real revenue opportunity in post-inspection services: reviewing reports, identifying appealable items, building documentation packages.'},
    {q:'What documentation should be maintained for every repair made on a client property?',opts:['Just the contractor\'s verbal confirmation','Work orders with completion dates, contractor invoices, and time-stamped photographs','A tenant signature acknowledging the repair','Only documentation for items over $1,000'],ans:1,exp:'Maintain work orders (date requested, date completed, technician), contractor invoices for third-party work, and time-stamped photographs of the completed repair. This documentation package supports both appeals and proactive dispute resolution.'},
    {q:'A REAC inspection finds an outlet with an "open ground" reading, but an electrician confirms that a GFCI breaker upstream covers that circuit. What should you do?',opts:['Accept the citation — the tester showed an issue','Appeal it with the electrician\'s documentation showing upstream GFCI protection provides the required protection','Replace the outlet and don\'t appeal','Ask for a re-inspection'],ans:1,exp:'Upstream GFCI protection is valid protection even if the outlet tester shows "open ground." An electrician\'s documentation confirming the upstream GFCI covers that circuit is strong appeal evidence.'},
    {q:'What is the recommended pricing for Phase 4 — Post-Inspection Appeals?',opts:['$250–500 per deficiency appealed','Flat fee $1,000–2,500 per appeal package','Percentage of points recovered','Included free with the original pre-inspection walkthrough'],ans:1,exp:'Post-inspection appeals are typically priced at a flat fee of $1,000–2,500 per appeal package — covering report review, deficiency identification, documentation compilation, and appeal submission.'},
    {q:'Which referral source is most likely to send you multiple properties rather than just one?',opts:['An individual HCV landlord with one property','A property management company managing 5 or more affordable housing properties','A tenant association','A real estate photographer'],ans:1,exp:'Property management companies managing multiple affordable housing properties are the highest-leverage referral relationships — one contact equals multiple properties, and your service can be deployed across their entire portfolio.'},
    {q:'What is the annual retainer service and why does it create recurring revenue?',opts:['A one-time setup fee for new clients','Ongoing services including annual POA self-inspection, quarterly walkthroughs, and staff training — billed monthly because properties have ongoing compliance obligations every year','A subscription to your NSPIRE training materials','A monthly fee for being listed in your referral directory'],ans:1,exp:'The annual retainer provides ongoing services (POA self-inspection, quarterly walks, training) on a monthly flat rate. Properties have annual compliance obligations, so your service renews naturally. This is your most valuable revenue stream per client.'},
    {q:'How should you frame a pre-inspection service proposal to a LIHTC syndicator approaching a year-15 audit?',opts:['Focus on the low cost of the service','Emphasize that you can help them understand NSPIRE basics','Show that their investment asset needs to pass inspection to maintain compliance and protect equity — your service is asset protection, not just inspection prep','Focus on the aesthetics of their properties'],ans:2,exp:'LIHTC investors approaching year-15 are protecting a significant real estate asset. Frame your service as asset protection and compliance management — not just "inspection prep." The financial stakes justify a premium service engagement.'},
    {q:'When should you reach out to a property that just received a failed REAC inspection score?',opts:['Wait 6 months until they have processed the failure','Reach out immediately — they are in their highest-urgency window and most motivated to hire help','Only reach out if they contact you first','Wait until their corrective action plan deadline has passed'],ans:1,exp:'Immediately. A property that just failed is in their highest-urgency window. They have a corrective action plan to file, a follow-up inspection coming, and the pain of failure is fresh. This is the easiest conversion opportunity in the market.'},
  ]},

  ch9: { title:'Chapter 9 Quiz — Unit Deficiencies: Complete Standards', questions:[
    {q:'How many working outlets does each habitable room require under NSPIRE?',opts:['One outlet minimum','Two working outlets, OR one outlet plus one permanently installed light fixture','Three outlets minimum','No minimum — just functional wiring'],ans:1,exp:'Each habitable room needs two working outlets, OR one working outlet plus one permanently installed light fixture. Check every bedroom, living room, and dining area.'},
    {q:'An outlet tester shows "open ground" on a bathroom three-prong outlet. Severity?',opts:['Low','Moderate','Severe','Life-Threatening'],ans:2,exp:'Open ground on a three-prong outlet = Severe. Removes the safety ground that protects residents from electrical shock.'},
    {q:'Two wires are connected to one circuit breaker in a unit\'s electrical panel (double-tapped). Severity?',opts:['Low — common in older buildings','Moderate','Severe — creates overload and fire risk','Life-Threatening'],ans:2,exp:'Double-tapped breakers (two wires on one breaker) = Severe. Creates circuit overload risk and is an electrical code violation that can cause fires.'},
    {q:'All four stove burners are non-functional. Severity?',opts:['Low','Moderate','Severe — complete loss of cooking capability','Life-Threatening'],ans:2,exp:'No burners working at all = Severe. If at least one burner works, the deficiency is Moderate. Complete loss of cooking capability escalates severity.'},
    {q:'A toilet rocks slightly when you press on the sides. Severity?',opts:['Not cited — cosmetic only','Low — can break the wax seal and cause leaks','Moderate — plumbing concern','Severe — health hazard'],ans:1,exp:'A rocking toilet = Low. It can break the wax seal and cause leaks and water damage, but isn\'t an immediate health hazard. Fix it to prevent the Low from becoming a Moderate water damage issue.'},
    {q:'There is no hot water at the kitchen and bathroom faucets in a unit. The water heater is cold. Severity?',opts:['Low — inconvenience only','Moderate','Severe — no hot water supply','Life-Threatening'],ans:2,exp:'No hot water in a unit = Severe. Run the hot water at every faucet during your pre-inspection walkthrough. Test hot water, don\'t just assume.'},
    {q:'You find soft, spongy flooring directly around the base of the toilet in a unit. What does this indicate?',opts:['Normal wear and tear — Low deficiency','Active or past water leak from the toilet wax ring or supply line — Moderate to Severe depending on extent','Structural floor failure — Life-Threatening','Not cited under NSPIRE'],ans:1,exp:'Soft flooring around a toilet indicates water damage from a leaking wax ring or supply line. This is Moderate to Severe — find the active source, document extent of damage, and flag for plumbing repair plus subfloor evaluation.'},
    {q:'Mold is found in the bathroom caulk lines around the tub. Severity?',opts:['Low — surface cosmetic','Moderate','Severe — chronic health risk','Life-Threatening in all cases'],ans:2,exp:'Mold = Severe in most cases. Can escalate to Life-Threatening with vulnerable residents. Fix the moisture source (caulking failure allows water infiltration) before treating the mold.'},
    {q:'A bathroom has no exhaust fan AND the window does not open. Severity?',opts:['Low','Moderate — no functional ventilation in a wet area','Severe','Life-Threatening'],ans:1,exp:'No functional ventilation in a bathroom (no fan AND no operable window) = Moderate. Without ventilation, moisture accumulates and leads directly to mold.'},
    {q:'An extension cord is run through the wall to power a permanently mounted light fixture. Severity?',opts:['Low — the light works fine','Moderate to Severe — extension cords cannot substitute for permanent wiring','Life-Threatening — immediate fire hazard','Not cited if the cord is properly rated'],ans:1,exp:'Extension cords used as permanent wiring substitutes = Moderate to Severe. This is an electrical code violation and fire hazard. The light working is irrelevant — the means of powering it is the deficiency.'},
    {q:'A kitchen sink has hot water but no cold water. Severity?',opts:['Not cited — hot water is the key requirement','Low','Moderate — functional failure of the cold water supply','Severe'],ans:2,exp:'The sink must have both hot and cold water. Missing cold water = Moderate functional failure. Check both temperatures at every sink during your walkthrough.'},
    {q:'You turn on a permanently installed kitchen ceiling light and it doesn\'t work. You replace the bulb and it still doesn\'t work. Severity?',opts:['Low — dead bulb only','Moderate — permanently installed fixture inoperable','Severe','Life-Threatening'],ans:1,exp:'Permanently installed fixture inoperable (confirmed after bulb replacement) = Moderate. Approximately 2.6 per 100 units. Check kitchen and bathroom fixtures specifically.'},
    {q:'Peeling paint is found in a hallway of a building constructed in 1965. What should you do?',opts:['Note it as a Low cosmetic deficiency only','Cite it as Moderate under NSPIRE AND flag the lead paint regulatory trigger — lead-safe work practices required','Ignore it — hallway paint is not inspected','Require immediate professional lead abatement'],ans:1,exp:'Pre-1978 peeling paint = Moderate under NSPIRE AND triggers lead paint regulations (24 CFR Part 35). Lead-safe work practices are required for all repairs. This is two separate compliance issues, not one.'},
    {q:'A bedroom door cannot close to provide privacy. Severity?',opts:['Not cited — interior doors are not inspected','Low — does not meet the functional adequacy standard','Moderate — privacy is a habitability issue','Severe'],ans:1,exp:'An interior bedroom door that cannot close for privacy = Low. Interior doors within a unit are inspected for basic functionality. A door that cannot close at all fails the functional adequacy standard.'},
    {q:'A refrigerator provided by the property owner is warm — not maintaining temperature. Severity?',opts:['Not cited — appliances are resident responsibility','Low','Moderate — owner-provided refrigerator must function','Severe'],ans:2,exp:'If a refrigerator is provided by the owner/property as part of the unit, it must function. A warm refrigerator = Moderate. Note: if the unit does not include a refrigerator per the lease, it is not inspected.'},
  ]},

  ch10: { title:'Chapter 10 Quiz — Inside (Common Area) Deficiencies', questions:[
    {q:'A fire door in a stairwell is propped open with a wooden wedge. Severity?',opts:['Low — a wedge is removable','Moderate','Severe — fire doors must self-close and latch','Life-Threatening'],ans:2,exp:'Propped fire door = Severe. Fire doors must self-close and latch to perform their fire separation function. Most commonly cited inside deficiency.'},
    {q:'Emergency lighting in an exit stairwell has dead batteries and won\'t illuminate during a test. Severity?',opts:['Low','Moderate','Severe — required for egress during power failures','Life-Threatening'],ans:2,exp:'Non-functional emergency lighting = Severe. These battery-backup lights must illuminate egress paths when power fails.'},
    {q:'The EXIT sign over the main building exit is present but partially dark — one letter is burnt out. Severity?',opts:['Low — still partially visible','Moderate','Severe — exit signs must be fully illuminated','Life-Threatening'],ans:2,exp:'Exit signs must be fully illuminated. Burnt-out lamp = Severe because residents and emergency responders rely on exit signs during emergencies.'},
    {q:'A dryer duct in the laundry room is disconnected from the exterior vent. Severity?',opts:['Low — cosmetic duct issue','Moderate — disconnected duct is a fire hazard from lint accumulation','Severe','Life-Threatening'],ans:1,exp:'Disconnected or clogged dryer duct = Moderate. Lint accumulation in an unvented duct is a documented fire hazard. Reconnect and clear any lint accumulation.'},
    {q:'A call-for-aid pull cord in a senior property bathroom is tied up above 6 inches from the floor. Severity?',opts:['Low','Moderate','Severe (non-scoring)','Life-Threatening'],ans:2,exp:'Pull cord tied so it cannot be engaged = Severe (non-scoring). Still requires correction even though it doesn\'t deduct points. Residents in emergencies need this to function.'},
    {q:'A common stairwell handrail is loose — it moves when you apply lateral pressure. Severity?',opts:['Low — handrails are often loose in older buildings','Moderate','Severe — loose handrail cannot support a falling resident','Life-Threatening'],ans:2,exp:'Loose or insecurely anchored handrail = Severe. A handrail that gives way when grabbed by a falling resident provides no protection and can worsen the fall.'},
    {q:'Combustible boxes are stored within 12 inches of the boiler in the mechanical room. Severity?',opts:['Low — just clutter','Moderate','Severe — combustibles within 18 inches of boiler flame create fire risk','Life-Threatening'],ans:2,exp:'Combustible materials within 18 inches of boiler/water heater flames = Severe fire hazard. The mechanical room must be clear of all combustibles near heat-producing equipment.'},
    {q:'An exit door in a common area is chained and padlocked from the inside. Severity?',opts:['Moderate — locked doors are common','Severe','Life-Threatening — blocked egress path','It depends on whether there is another exit'],ans:2,exp:'An exit door that cannot be opened from inside = Life-Threatening. This directly blocks a required egress path. Residents cannot escape a fire if exit doors are padlocked from inside.'},
    {q:'Common area hallway lights are non-functional on an entire floor. Severity?',opts:['Low — non-urgent cosmetic','Moderate — affects safety in hallways','Severe','Life-Threatening'],ans:1,exp:'Non-functional common area lighting = Moderate. Dark hallways and stairwells create fall and security hazards. This is one of the most commonly cited and most easily corrected inside deficiencies.'},
    {q:'A fire door\'s label is missing but the door is present, self-closes, and latches. Severity?',opts:['Severe — missing fire label is always Severe','Moderate — door functions but label is missing','Low — label is cosmetic if door functions','Life-Threatening'],ans:1,exp:'Fire door missing the required fire label = Moderate. The label certifies that the door meets fire rating standards. A door without a label may not actually meet those standards even if it looks functional.'},
    {q:'An electrical panel cover in the building\'s mechanical room is missing, exposing live bus bars. Severity?',opts:['Moderate — in a locked room','Severe','Life-Threatening — exposed live electrical components','Low — only maintenance staff enter'],ans:2,exp:'Missing panel cover exposing live components = Life-Threatening. It doesn\'t matter if the room is typically restricted — the standard applies regardless of access level.'},
    {q:'Storage items are stacked in the exit corridor reducing the path width to 28 inches. Severity?',opts:['Low — residents can still pass','Moderate','Severe — partially blocked egress','Life-Threatening if fully blocked'],ans:2,exp:'A partially blocked egress corridor = Severe. Exit paths must be kept clear. Severe blocking that prevents exit entirely could escalate to Life-Threatening.'},
    {q:'What is the most effective first action when you find a fire door propped open during your pre-inspection?',opts:['Document it and add it to the punch list for later','Remove the wedge immediately AND add it to the punch list for staff training','Report it to the local fire marshal','Leave it — residents propped it open for a reason'],ans:1,exp:'Remove the wedge immediately (a 5-second fix) AND add it to the punch list for staff training. If the door is propped open during your visit, it is being propped open regularly — the fix is behavioral training, not just physical repair.'},
    {q:'A shared laundry room has outlets next to the washing machines with no GFCI protection. Severity?',opts:['Low — washers are plugged in safely','Moderate','Severe — outlets within 6 feet of water source require GFCI','Life-Threatening'],ans:2,exp:'Laundry room outlets near washers = Severe if within 6 feet of water and unprotected. GFCI protection is required in laundry rooms. Check all laundry room outlets during your inside area inspection.'},
    {q:'Which item would be found in the Inside area inspection — NOT in the Unit or Outside areas?',opts:['Kitchen GFCI outlet','Bedroom egress window','Boiler room combustible storage','Exterior handrail'],ans:2,exp:'Boiler room combustible storage is an Inside area item — inside the building but not inside a unit. Kitchen GFCI and bedroom egress windows are Unit items. Exterior handrails are Outside items.'},
  ]},

  ch11: { title:'Chapter 11 Quiz — Outside Deficiencies: Complete Standards', questions:[
    {q:'A playground has asphalt directly under the swing set instead of impact-absorbing safety surfacing. Severity?',opts:['Low — common in older properties','Moderate','Severe — falls onto hard surfaces cause serious injuries','Not cited under NSPIRE'],ans:2,exp:'Hard surfacing directly under playground equipment = Severe. Children falling from swings or climbing equipment onto concrete or asphalt face serious injury risk.'},
    {q:'An exterior handrail on the building\'s front entry steps is missing. Mounting holes are visible in the concrete. Severity?',opts:['Low','Moderate','Severe','Life-Threatening — 24 hour fix'],ans:3,exp:'Exterior handrail missing with evidence of prior installation = Life-Threatening. Same rule as inside — mounting evidence (holes, paint shadow, anchors) triggers LT classification.'},
    {q:'Decorative fencing around a garden area is damaged. Severity?',opts:['Moderate — property appearance issue','Low','Severe','Not cited — decorative fencing is not scored under NSPIRE'],ans:3,exp:'Non-security, non-safety decorative fencing damage is NOT cited under NSPIRE. This was removed from scoring. Only security and safety fencing (pool enclosures, perimeter security) is inspected.'},
    {q:'An exterior electrical panel has a missing cover exposing live bus bars. Severity?',opts:['Moderate — outdoors, less accessible','Severe','Life-Threatening — exposed live components','Low'],ans:2,exp:'Missing panel cover exposing live components = Life-Threatening. The outdoor location does not reduce the severity — exposed live electrical is always LT regardless of location.'},
    {q:'A raised section of sidewalk (about 1.5 inches) near the building entrance creates an obvious trip hazard. Severity?',opts:['Not cited','Low','Moderate — significant trip hazard','Severe'],ans:2,exp:'A significant trip hazard on a walkway = Moderate. Minor cracking without raised edges is Low. The test is whether an actual trip hazard exists. 1.5 inches is significant.'},
    {q:'Pool enclosure fencing has a 3-foot gap that allows access to the pool. Severity?',opts:['Low — pools are supervised','Moderate','Severe — safety fencing must be complete to prevent unauthorized access','Life-Threatening'],ans:2,exp:'Pool enclosure fencing with gaps = Severe. Pool safety fencing is required to prevent unsupervised access — particularly by children. Gaps in pool fencing are a significant drowning risk.'},
    {q:'Graffiti covers a large section of the building\'s exterior wall. Severity?',opts:['Moderate — property appearance concern','Low','Severe in high-visibility locations','Not cited — graffiti was removed from NSPIRE'],ans:3,exp:'Graffiti is completely removed from NSPIRE — not cited at all, regardless of location, extent, or content. Do not waste client resources on graffiti removal for NSPIRE purposes.'},
    {q:'An exterior stair tread is cracked and partially missing, creating an uneven walking surface. Severity?',opts:['Low','Moderate to Severe — damaged stair tread creates fall risk','Life-Threatening','Not cited — exterior stairs are not inspected'],ans:1,exp:'Damaged exterior stair tread = Moderate to Severe depending on the severity of the hazard. Exterior stairs are inspected as part of the Outside area.'},
    {q:'Parking lot lighting is completely non-functional. Severity?',opts:['Not cited — parking lot lighting is not in NSPIRE','Low','Moderate — security and safety concern without lighting','Severe'],ans:2,exp:'Non-functional parking lot lighting = Moderate. The question is whether functional safety lighting is present — the standard focuses on security and safety function, not illumination level.'},
    {q:'A playground slide has a bolt end protruding from the side of the slide chute. Severity?',opts:['Low — small hardware issue','Moderate','Severe — exposed hardware on playground equipment creates laceration risk','Life-Threatening'],ans:2,exp:'Exposed hardware (bolt ends) on playground equipment = Severe. Children can cut themselves on protruding bolts during play. This is a specific playground equipment safety deficiency.'},
    {q:'What is the correct approach to exterior caulking that is cracked and missing in several locations on the building?',opts:['Cite it as a Low deficiency and include it on the punch list','Do not include it on the punch list — exterior caulking damage is not cited under NSPIRE','Cite it as Moderate because water infiltration is a concern','Treat it as Severe in pre-1978 buildings'],ans:1,exp:'Exterior caulking damage is NOT cited under NSPIRE. Do not include it on your punch list. Redirect client maintenance dollars to scored items.'},
    {q:'A gas meter on the exterior of the building has a detectable gas odor near it. Severity?',opts:['Low — gas meters occasionally vent naturally','Moderate','Severe','Life-Threatening — treat the same as an interior gas leak'],ans:3,exp:'Detectable gas odor at an exterior gas meter = Life-Threatening. Treat exactly the same as an interior gas leak — stop the inspection, evacuate, and call the gas utility and fire department.'},
    {q:'Rodent burrow holes are found along the building foundation near trash areas. What is the concern?',opts:['Not cited — pest evidence outside is not part of NSPIRE','Low — outdoor pests only','The exterior pest evidence may be linked to interior infestation, which is Severe','Moderate — exterior appearance only'],ans:2,exp:'Exterior rodent burrows near the foundation suggest active rodent activity that is very likely connected to interior infestation. Note it in your punch list and specifically inspect all units near that area of the building for interior evidence.'},
    {q:'An outdoor GFCI outlet on the building exterior does not have a weatherproof cover. Severity?',opts:['Not cited — outdoor outlets are maintenance items','Low','Moderate to Severe depending on location — outlets near water or in exposed locations require weatherproof covers','Life-Threatening'],ans:2,exp:'Outdoor outlet without weatherproof cover = Moderate to Severe. Outdoor outlets are exposed to moisture and require weatherproof covers to prevent water infiltration into the electrical box.'},
    {q:'What three outside items should you ALWAYS check first on any property pre-inspection?',opts:['Parking lot, vegetation, exterior paint','Playground equipment and surfacing, exterior handrails, exterior electrical panels','Mailboxes, fencing, exterior lighting','Dumpster areas, sidewalks, exterior caulking'],ans:1,exp:'Playground (Severe if surfacing is wrong), exterior handrails (LT if missing with evidence), and exterior electrical panels (LT if covers missing) are the three outside items most likely to produce high-severity findings. Check these first.'},
  ]},

  ch12: { title:'Chapter 12 Quiz — Elevator Standards & Certificates', questions:[
    {q:'An elevator certificate expired 3 months ago. Severity?',opts:['Low — paperwork only','Moderate','Severe — expired certificate means operating without required annual safety inspection','Life-Threatening'],ans:2,exp:'Expired elevator certificate = Severe. The elevator has been operating without its required annual safety inspection and certification.'},
    {q:'The emergency phone inside the elevator cab does not work when tested. Severity?',opts:['Low','Moderate','Severe — residents must be able to call for help if trapped','Life-Threatening'],ans:2,exp:'Non-functional elevator emergency phone = Severe. If a resident is trapped between floors, they must be able to call for help.'},
    {q:'Where must the elevator inspection certificate be located?',opts:['In the property manager\'s office only','Posted inside the elevator cab or in a location accessible to the inspector','Filed with the local building department — no on-site copy needed','The elevator company keeps it on file'],ans:1,exp:'The certificate must be posted in the cab or accessible to the inspector. A certificate that exists but is not accessible at the time of inspection still constitutes a deficiency.'},
    {q:'Standing water is found in the elevator pit. Severity?',opts:['Low — common in older buildings','Moderate to Severe — equipment corrosion and electrical hazard','Severe only if over 2 inches deep','Not cited under NSPIRE'],ans:1,exp:'Standing water in elevator pit = Moderate to Severe. Causes equipment corrosion and creates electrical hazards when water reaches electrical components.'},
    {q:'The elevator consistently stops 2.5 inches above the floor landing instead of level. Severity?',opts:['Low — acceptable variation','Moderate to Severe — significant mis-leveling is a trip hazard','Not cited — slight variations are normal','Life-Threatening'],ans:1,exp:'Significant elevator mis-leveling = Moderate to Severe. It creates a trip hazard when residents board or exit, especially dangerous for elderly residents and those using mobility aids.'},
    {q:'What should you check first when verifying elevator compliance during a pre-inspection?',opts:['Ride the elevator and test the emergency phone','Verify the certificate is present, posted, and not expired','Check the machine room temperature','Inspect the pit for water'],ans:1,exp:'Always start with the certificate. A missing or expired certificate is a Severe deficiency that can be identified in seconds. If the certificate is not current, schedule the inspection immediately — it takes weeks to get scheduled.'},
    {q:'An elevator door opens but takes 8 seconds to begin closing after releasing. Severity?',opts:['Not cited — door timing is not inspected','Low','Moderate — door timing may indicate sensor or motor issues','Severe — door operation is safety-critical'],ans:2,exp:'Elevator door operation issues — including abnormal timing — are Moderate to Severe depending on whether they indicate a safety system problem. Doors that don\'t close properly or close too slowly often indicate door motor or safety edge sensor issues.'},
    {q:'The elevator machine room is being used to store maintenance supplies and cleaning equipment. Severity?',opts:['Not cited — convenient storage','Low to Moderate — machine rooms must be accessible and not used for storage','Severe','Life-Threatening'],ans:1,exp:'Machine room used for storage = Low to Moderate. The room must be accessible and clear. Clutter interferes with maintenance access and can create fire hazards near electrical equipment.'},
    {q:'An elevator\'s cab interior has a significant hole in the wall panel. Severity?',opts:['Not cited — cosmetic only','Low — cab interior damage','Moderate — cab must be maintained in safe and functional condition','Severe'],ans:2,exp:'Significant cab interior damage = Low to Moderate. The cab interior must be maintained — damaged panels, non-functional lighting, and trip-hazard flooring are all cited. A hole in a wall panel is at minimum Low, and Moderate if it exposes mechanical components.'},
    {q:'When should you call an elevator contractor during a pre-inspection rather than just noting it on the punch list?',opts:['Only if the elevator is completely not running','For expired certificate, non-functional doors, non-functional emergency phone, or standing water in pit — these need immediate attention','Only after the official REAC inspection identifies items','Only if a resident has filed a complaint'],ans:1,exp:'Call immediately for: expired certificate (takes weeks to schedule), door malfunctions (safety-critical), non-functional emergency phone (Severe), or standing water in pit (escalating damage). Don\'t wait for the REAC inspection.'},
    {q:'An elevator has a current certificate but the certificate shows two outstanding deficiency orders from the last inspection. What does this mean?',opts:['The deficiency orders are part of the normal process — nothing to act on','The elevator inspector found specific items requiring correction — these must be resolved before or instead of the next scheduled inspection','Outstanding deficiency orders only apply to the elevator company, not the property owner','The certificate is still valid and no action is needed'],ans:1,exp:'Outstanding deficiency orders on an elevator certificate mean specific items were cited by the elevator inspector that require correction. Review the orders carefully and coordinate with your elevator contractor to resolve each one.'},
    {q:'A 20-story building has an elevator that is currently out of service for repairs. How does this affect your pre-inspection assessment?',opts:['Ignore it — out of service elevators are not cited','Document it, confirm a service timeline with the elevator contractor, and prioritize getting it back in service before the REAC inspection','It is only a problem for upper-floor residents','Cite it as Low since the building is not at risk'],ans:1,exp:'An out-of-service elevator must be documented, confirmed for active repair, and prioritized for completion before the REAC inspection. An elevator that is out of service on inspection day will be cited as a Severe deficiency, and in a high-rise building affects all upper-floor residents.'},
    {q:'What type of elevator maintenance contract provides the most protection against unexpected failures before an inspection?',opts:['An oil-and-grease-only contract — cheapest option','A full-maintenance contract (parts and labor included) — reduces risk of surprise failures','A time-and-materials contract — pay only when repairs are needed','No contract — hire as needed'],ans:1,exp:'Full-maintenance contracts (parts and labor included) are more expensive but dramatically reduce the risk of surprise equipment failures. For a property with an upcoming REAC inspection, an oil-and-grease-only contract leaves major repair costs unpredictable.'},
    {q:'What does elevator mis-leveling at the floor mean for your client\'s residents?',opts:['It is a cosmetic issue with no practical impact','It creates a trip hazard — particularly dangerous for elderly residents and those using wheelchairs or walkers','It only matters if the elevator stops more than 6 inches from level','It affects elevator motor efficiency but not resident safety'],ans:1,exp:'Elevator mis-leveling creates a trip hazard when residents step on or off — particularly dangerous for elderly residents, residents with mobility limitations, and those using wheelchairs or walkers. This is why it is Moderate to Severe depending on extent.'},
    {q:'What is the complete elevator pre-inspection checklist you should use on every property?',opts:['Just ride it and test the emergency phone','Certificate posted and current, no outstanding deficiency orders, emergency phone works, cab lighting works, doors open/close fully with safety edge functioning, elevator levels at each floor, machine room accessible and clean, no water in pit, maintenance contract current'],ans:1,exp:'The complete checklist: certificate present and not expired, no outstanding orders, emergency phone functional, cab lighting works, doors operate correctly with safety edge, proper leveling at each floor, clean machine room, dry pit, and current maintenance contract.'},
  ]},

  ch13: { title:'Chapter 13 Quiz — Boiler, HVAC & Fire System Standards', questions:[
    {q:'A sprinkler control valve is found in the closed position. Severity?',opts:['Low — valve position is a maintenance detail','Moderate','Severe — closed valve disables the sprinkler system for that zone','Life-Threatening'],ans:2,exp:'Closed sprinkler control valve = Severe. Disables the fire suppression system. All control valves must be in the open position and tagged as such.'},
    {q:'Sprinkler heads in a mechanical room have been painted over. Severity?',opts:['Low — cosmetic only','Moderate','Severe — paint clogs the heat-sensitive element preventing activation','Life-Threatening'],ans:2,exp:'Painted sprinkler heads = Severe. Paint fills the heat-sensitive fusible element and prevents the head from activating during a fire.'},
    {q:'How often must fire sprinkler systems be inspected under NFPA 25?',opts:['Annually only','Quarterly for gauges and control valves, annually for the full system, every 5 years for internal pipe inspection','Only every 5 years','Monthly'],ans:1,exp:'NFPA 25 requires quarterly inspection of gauges and control valves, annual full system inspection, and 5-year internal pipe inspections.'},
    {q:'A boiler pressure relief valve is missing. Severity?',opts:['Low — rarely needed','Moderate','Severe — PRV is a critical safety device preventing over-pressurization','Life-Threatening'],ans:2,exp:'Missing PRV = Severe. The pressure relief valve prevents dangerous over-pressurization. Without it, boiler pressure can build to catastrophic levels.'},
    {q:'How far must storage be kept from sprinkler heads to avoid obstruction?',opts:['6 inches','12 inches','18 inches','24 inches'],ans:2,exp:'Storage must be kept at least 18 inches below sprinkler heads to ensure the spray pattern fully develops and reaches the fire. Less than 18 inches = Severe.'},
    {q:'A fire alarm annual inspection report shows the last inspection was 14 months ago. Severity?',opts:['Low — close enough','Moderate — annual inspection is overdue','Severe','Life-Threatening'],ans:1,exp:'Fire alarm systems must be inspected annually under NFPA 72. An inspection report that is 14 months old = Moderate. Schedule the inspection immediately — it typically takes 1–2 weeks to schedule.'},
    {q:'A fire extinguisher in a common hallway has an inspection tag dated 18 months ago. Severity?',opts:['Low — recent enough','Moderate — annual inspection required','Severe','Life-Threatening'],ans:1,exp:'Fire extinguisher inspection tags must be within the past 12 months. Expired tag = Moderate in most locations. Schedule the annual extinguisher inspection service.'},
    {q:'The boiler room has a combustion air opening that was sealed with foam insulation by a previous contractor. What is the risk?',opts:['No risk — better insulation is good','Low — slight efficiency impact','Severe to Life-Threatening — blocked combustion air causes incomplete combustion and carbon monoxide production','Moderate — cosmetic issue'],ans:2,exp:'Blocked combustion air = Severe to Life-Threatening. Gas and oil-fired boilers require adequate combustion air. Sealing combustion air openings causes incomplete combustion, which produces carbon monoxide — a colorless, odorless, lethal gas.'},
    {q:'During a pre-inspection, you find the fire alarm panel has a solid red "TROUBLE" light. What should you do?',opts:['Note it as Low and move on','Contact the fire alarm contractor immediately — a trouble condition indicates a system fault that must be diagnosed and corrected','Ask the property manager if it has always been like that','Only report it if the inspection date is within 30 days'],ans:1,exp:'A fire alarm TROUBLE condition = active system fault requiring immediate diagnosis. Contact the fire alarm contractor right away. Do NOT ignore trouble lights. A fire alarm in fault condition may not operate correctly in an emergency.'},
    {q:'A storage room adjacent to a boiler room has cardboard boxes stacked to within 6 inches of the boiler. Severity?',opts:['Low — storage rooms are separate from the boiler','Moderate','Severe — combustibles must be kept 18 inches from boiler flames','Life-Threatening'],ans:2,exp:'Combustible materials within 18 inches of boiler/water heater flames = Severe fire hazard. The 18-inch clearance rule applies regardless of whether the combustibles are in an adjacent room if the boiler flame could reach them.'},
    {q:'Which type of fire extinguisher is required in a community kitchen area used for cooking with oils?',opts:['ABC dry chemical — standard for all locations','Class K — required where cooking oils or fats may ignite','CO2 only — for electrical equipment','Any extinguisher works equally'],ans:1,exp:'Class K fire extinguishers are required where cooking oils and fats are used — community kitchens with ranges or fryers. Standard ABC dry chemical is not effective on Class K (cooking oil) fires.'},
    {q:'The boiler has a current certificate, but the backflow preventer on the cold water fill line is missing. Severity?',opts:['Low — backflow preventers are optional','Moderate to Severe — required to prevent backflow of heating system water into the potable water supply','Not cited under NSPIRE','Only required if the building is over 3 stories'],ans:1,exp:'Missing backflow preventer on boiler fill line = Moderate to Severe. Required to prevent heating system water (which may contain treatment chemicals) from flowing back into the potable water supply.'},
    {q:'What is the correct documentation file you should verify for the fire sprinkler system during a pre-inspection?',opts:['Only the original installation permit','Current inspection report from a licensed contractor (within required timeframe), no outstanding deficiency orders, and confirmation that all control valves are open','Just verify sprinkler heads are visible','Only required if the building is over 6 stories'],ans:1,exp:'Verify: current inspection report from a licensed contractor (within timeframe per NFPA 25), no outstanding deficiency items from the last inspection, and all control valves in open position and properly tagged.'},
    {q:'A cooling tower on the building roof has standing water with visible biological growth. What is the health concern?',opts:['None — cooling towers always have water','Moderate appearance issue only','Legionella bacteria can grow in improperly maintained cooling tower water — potential respiratory disease risk','Low — outdoor equipment'],ans:2,exp:'Improperly maintained cooling tower water can harbor Legionella bacteria, which causes Legionnaires\' disease — a serious and potentially fatal respiratory illness. Properties with cooling towers may have specific water treatment and testing requirements.'},
    {q:'Which documents should be in a complete boiler compliance file on every property?',opts:['Current boiler certificate and manufacturer\'s manual only','Current boiler certificate matched to equipment serial number, pressure relief valve documentation, maintenance/service records, and repair history'],ans:1,exp:'Complete boiler file: current certificate matching the specific equipment (by serial number), PRV documentation, maintenance service records, and repair history. If a boiler was replaced, the certificate must be updated for the new equipment.'},
  ]},
}
